(function(){if(window.webScraperUI){alert('Scraper is already open!');return;}const overlay=document.createElement('div');overlay.id='webScraperOverlay';overlay.style.cssText='position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.8);z-index:999999;display:flex;align-items:center;justify-content:center;';const panel=document.createElement('div');panel.style.cssText='background:white;border-radius:12px;padding:30px;max-width:500px;width:90%;max-height:90vh;overflow-y:auto;box-shadow:0 10px 40px rgba(0,0,0,0.3);';panel.innerHTML='<h2 style="margin:0 0 20px 0;color:#667eea;">🌐 整页批量采集</h2><div style="margin-bottom:15px;"><label style="display:block;margin-bottom:5px;font-weight:600;">📄 正文CSS选择器:</label><input id="scraperContent" type="text" value="article, .article, .content, #article, #content, [class*=\'content\'], [id*=\'content\'], [class*=\'article\'], [id*=\'article\']" style="width:100%;padding:10px;border:2px solid #e0e0e0;border-radius:6px;"/><small style="color:#666;">匹配正文区域</small></div><div style="margin-bottom:15px;"><label style="display:block;margin-bottom:5px;font-weight:600;">🎯 标题CSS选择器:</label><input id="scraperTitle" type="text" value="#title, .title, [class*=\'title\'], [id*=\'title\']" style="width:100%;padding:10px;border:2px solid #e0e0e0;border-radius:6px;"/><small style="color:#666;">匹配文章标题</small></div><div style="margin-bottom:15px;"><label style="display:block;margin-bottom:5px;font-weight:600;">🔤 下一页匹配正则:</label><input id="scraperNextPattern" type="text" value="下.*页|下.*章|下.*节" style="width:100%;padding:10px;border:2px solid #e0e0e0;border-radius:6px;"/><small style="color:#666;">正则匹配下一页/下一章/下一节</small></div><div style="margin-bottom:15px;"><label style="display:block;margin-bottom:5px;font-weight:600;">🔢 最大采集页数:</label><input id="scraperMaxPages" type="text" value="300" style="width:100%;padding:10px;border:2px solid #e0e0e0;border-radius:6px;-moz-appearance:none;-webkit-appearance:none;appearance:none;"/><small style="color:#666;">手动输入数字，无加减按钮</small></div><div style="margin-bottom:15px;"><label style="display:block;margin-bottom:5px;font-weight:600;">💾 自定义文件名:</label><input id="scraperFilename" type="text" placeholder="默认使用网页标题" style="width:100%;padding:10px;border:2px solid #e0e0e0;border-radius:6px;"/></div><div style="display:flex;gap:10px;"><button id="scraperStart" style="flex:1;padding:12px;background:linear-gradient(135deg,#667eea,#764ba2);color:white;border:none;border-radius:6px;font-weight:600;cursor:pointer;">🚀 开始采集</button><button id="scraperClose" style="padding:12px 20px;background:#f44336;color:white;border:none;border-radius:6px;font-weight:600;cursor:pointer;">✕ 关闭</button></div><div id="scraperStatus" style="margin-top:15px;padding:10px;border-radius:6px;display:none;"></div>';overlay.appendChild(panel);document.body.appendChild(overlay);window.webScraperUI=overlay;function findNextUrlByRegex(doc,pattern){const reg=new RegExp(pattern,'i');const allLinks=doc.querySelectorAll('a');for(const link of allLinks){const text=link.textContent.trim();if(reg.test(text)){const href=link.getAttribute('href');if(href)return new URL(href,window.location.origin).href;}}return null;}function extractPageData(doc,titleSel,contentSel){let title='无标题';const titleEl=doc.querySelector(titleSel);if(titleEl)title=titleEl.textContent.trim();let content='无正文';const contentEls=doc.querySelectorAll(contentSel);if(contentEls.length>0){content=Array.from(contentEls).map(el=>el.textContent.trim()).join('\n\n');}return {title,fullText:`【${title}】\n\n${content}\n\n——————————————\n\n`};}async function fetchPageDoc(url){try{const res=await fetch(url,{credentials:'include'});const html=await res.text();return new DOMParser().parseFromString(html,'text/html');}catch(e){console.error('请求失败:',e);return null;}}async function scrape(){const contentSel=document.getElementById('scraperContent').value;const titleSel=document.getElementById('scraperTitle').value;const nextPattern=document.getElementById('scraperNextPattern').value;const maxPages=parseInt(document.getElementById('scraperMaxPages').value||300);const filename=document.getElementById('scraperFilename').value;const statusDiv=document.getElementById('scraperStatus');const startBtn=document.getElementById('scraperStart');startBtn.disabled=true;startBtn.textContent='⏳ 采集中...';statusDiv.style.display='block';statusDiv.style.background='#e3f2fd';statusDiv.style.color='#1976d2';let allText='';let currentUrl=window.location.href;let pageCount=0;let nextUrl=null;while(pageCount<maxPages){pageCount++;statusDiv.textContent=`正在采集第 ${pageCount}/${maxPages} 页`;const doc=await fetchPageDoc(currentUrl);if(!doc)break;const pageData=extractPageData(doc,titleSel,contentSel);allText+=pageData.fullText;nextUrl=findNextUrlByRegex(doc,nextPattern);if(!nextUrl)break;currentUrl=nextUrl;await new Promise(res=>setTimeout(res,600));}if(allText.trim()){const blob=new Blob([allText],{type:'text/plain;charset=utf-8'});const blobUrl=URL.createObjectURL(blob);const a=document.createElement('a');a.href=blobUrl;let defaultName=document.title.replace(/[^\u4e00-\u9fa5a-zA-Z0-9]/g,'_');let saveName=filename||defaultName||'采集文档';a.download=saveName+'.txt';a.click();URL.revokeObjectURL(blobUrl);statusDiv.style.background='#e8f5e9';statusDiv.style.color='#388e3c';statusDiv.textContent=`✅ 采集完成，共 ${pageCount} 页，已自动下载TXT`;}else{statusDiv.style.background='#ffebee';statusDiv.style.color='#c62828';statusDiv.textContent='❌ 未采集到内容，请检查选择器';}startBtn.disabled=false;startBtn.textContent='🚀 开始采集';}document.getElementById('scraperStart').onclick=scrape;document.getElementById('scraperClose').onclick=()=>{document.body.removeChild(overlay);window.webScraperUI=null;};})();
